// WF-YT: 입력 검증
var body = $input.first().json.body || $input.first().json;
var action = (body.action || 'getVideos').trim();
var count = Math.min(Math.max(parseInt(body.count) || 5, 1), 10);
var videoId = (body.video_id || '').trim();

if (action !== 'getVideos' && action !== 'getVideoProducts') {
  action = 'getVideos';
}

return [{ json: { action: action, count: count, videoId: videoId } }];

// 영상 + 상품 통합 응답 구성
var videosResp = $('Get Videos').first().json;
var productsResp = $input.first().json;

var videos = (videosResp && videosResp.list) ? videosResp.list : [];
var allProducts = (productsResp && productsResp.list) ? productsResp.list : [];

// 영상별 상품 매핑
var productsByVideo = {};
for (var i = 0; i < allProducts.length; i++) {
  var p = allProducts[i];
  var vid = p.video_id;
  if (!productsByVideo[vid]) productsByVideo[vid] = [];
  productsByVideo[vid].push({
    branduid: p.branduid || '',
    product_name: p.product_name || '',
    product_price: p.product_price || 0,
    product_image: p.product_image || '',
    product_url: p.product_url || ('/shop/shopdetail.html?branduid=' + (p.branduid || '')),
    source: p.source || 'keyword'
  });
}

// 응답 items 구성
var items = [];
for (var j = 0; j < videos.length; j++) {
  var v = videos[j];
  var videoId = v.video_id || '';
  var products = productsByVideo[videoId] || [];

  // 상품 source 결정
  var productSource = 'none';
  for (var k = 0; k < products.length; k++) {
    var src = products[k].source;
    if (src === 'description' || src === 'comment') { productSource = 'direct'; break; }
    if (src === 'keyword' && productSource !== 'direct') productSource = 'keyword';
  }

  // tags 파싱
  var tags = [];
  try { tags = JSON.parse(v.tags || '[]'); } catch(e) { tags = []; }

  items.push({
    id: videoId,
    title: v.title || '',
    publishedAt: v.published_at || '',
    viewCount: v.view_count || 0,
    thumbnail: 'https://img.youtube.com/vi/' + videoId + '/sddefault.jpg',
    tags: tags,
    matchedCategory: v.matched_category || '',
    products: products.slice(0, 4),
    productSource: productSource
  });
}

return [{ json: {
  status: 'success',
  items: items,
  timestamp: new Date().toISOString()
}}];
